head.script:
/**
 * ŪôĒ Ž©ī Ž™Ö : žěźžāįŽĻĄžö©žāįž†ēÍłįž§ÄŽďĪŽ°Ě
 * Ž©ĒŽČīÍ≤ĹŽ°ú : ŪöĆÍ≥Ą/ÍīÄŽ¶¨ŪöĆÍ≥Ą/žč§ž†ĀÍīÄŽ¶¨/žč§ž†ĀžßĎÍ≥Ą/žěźžāįŽĻĄžö©ÍīÄŽ¶¨/
 * ASISÍ≤ĹŽ°ú : /debis/dongwon-debis-engine/src/main/webapp/ac/co/rsltsmgnt/rsltsaggr/co_403_01_01b.jsp
 * žěĎ žĄĪ žěź : ŽįįÍłįžõź
 * žěĎ žóÖ žĚľ : 2025-12-02
 * žěĎžóÖŽāīžö© :
 *    1. ŪôĒŽ©īžĄłŪĆÖ
 *    2. žīąÍłįžĄłŪĆÖ(UDC)
 *    3. žä§ŪĀ¨Ž¶ĹŪäł TOBEž†ĄŪôė
 *    4. ÍłįŽä•ŪôēžĚł(Ž≤ĄŪäľ)
 *    5. [žôĄŽ£Ć]ŪôĒŽ©īŽ™©Ž°ĚžĚī treežěĄ(ŪĀ¨Íłįž°įž†ē)
 *    6. ŪäłŽ¶¨Ž∑į ŽįĎ ŪĖČž∂ĒÍįÄ, ŪĖČžā≠ž†ú Ž≤ĄŪäľ žěĎÍ≤Ć ŪēīžēľŪē®(sm žēąŽ®ĻŪěė)
 * žįłÍ≥†žā¨Ūē≠ :
 *    1. ‚ėŹ onbeforerowpositionchange žĚīŽ≤§Ūäłžóź $c.gus.cfValidate([tbl_asetCost]) ž≤ėŽ¶¨ žēąŽź®
 *    ‚ėě žĚľŽč® scwin.f_ValidationSync() ŽßĆŽď§žĖīžĄú ž≤ėŽ¶¨(scwin.setInit()žóź ds_list.reform() ŪēĄžąė, ž°įŪöĆ žčú žĚīŽ≤§Ūäł žēąŪÉúžõÄ)
 *    2. žÉĀžąėÍįí ÍįÄž†łžė§ŽäĒÍĪį žĖīŽĖĽÍ≤Ć Ūē†žßÄ? DGlobalValue.java žĚīŽüįÍĪį žěąžĚĄŽēĆŽßąŽč§ ÍįúŽįúžěźÍįÄ DGlobalValue.jsŽ°ú Ž≥ÄÍ≤ĹŪēīžĄú žė¨Ž†§žēľ ŪēėŽāė?
 * žąėž†ēžĚīŽ†• :
 *    - 2025-12-02      ŽįįÍłįžõź    žĶúžīąžěĎžĄĪ
 */

scwin.load_row  = 0; //ž°įŪöĆŪõĄ focusÍįÄÍ≤Ć Ūē† row
scwin.rootLevel = 1; //root level
scwin.maxLevel  = 10;

//žÉĀžąėÍįí(žěĄžčú)
scwin.DGlobalValue = { "ALL": -1, "TRUE": 1, "FALSE": 0 };

/**
 * TOBE : žīąÍłįŽ°úŽďú(UDC žěąžúľŽ©ī scwin.onUdcCompleted žīąÍłįÍįí žĄłŪĆÖ)
 */
scwin.onpageload = function() {

    const codeOptions = [
        { grpCd: "FI001", compID: "lc_acctClsCd" },       //Í≥Ąž†ēÍĶ¨Ž∂Ą
        { grpCd: "FI035", compID: "lc_asetCostLvl" },     //žěźžāįŽĻĄžö©Ž†ąŽ≤®
        { grpCd: "CO014", compID: "lc_aggrClsCd" }        //žßĎÍ≥ĄÍĶ¨Ž∂Ą
        ];
    $c.data.setCommonCode(codeOptions);
};

/**
 * žīąÍłįžĄłŪĆÖ(TOBE Í∑łŽ¶¨Žďú, žīĚÍĪīžąė)
 */
scwin.setInit = function() {
    ed_upperAsetCostCd.hidVal = "";    // žÉĀžúĄÍ≥Ąž†ēžĹĒŽďú ŪěąŽď†Íįí
    ed_mgntAcctCd.hidVal      = "";    // ÍīÄŽ¶¨Í≥Ąž†ēžĹĒŽďú ŪěąŽď†Íįí
    ds_master.removeAll();
    scwin.load_row = 0;

    $c.gus.cfDisableObjects(tbl_asetCost);
    $c.gus.cfDisableBtn([btn_addItem, btn_cancelItem, btn_update, btn_save]);
};


/**
 * UDCÍįí žīąÍłįŪôĒ(scwin.onpageload žĚīŪõĄ žĄłŪĆÖŽź®)
 */
 scwin.onUdcCompleted = function() {
    $c.gus.cfTurnCreateFlag(true);
    scwin.f_HeaderCreate();

    $c.gus.cfDisableObjects(tbl_asetCost);
    $c.gus.cfDisableBtn([btn_update, btn_save]);

    scwin.setInit();
    scwin.f_FieldClear();
    ed_srchAsetCostCd.focus();
 };

/**
 * ž°įŪöĆŪēĄŽďú CLEAR
 */
scwin.f_FieldClear = function() {
    scwin.f_SetSrchDefault();
};

/**
 * ž°įŪöĆ ÍłįŽ≥łÍįí žĄ§ž†ē
 */
scwin.f_SetSrchDefault = function() {
    lc_srchUseYn.setValue(scwin.DGlobalValue.TRUE);
    ed_srchAsetCostCd.setValue("");
    ed_srchAsetCostCdNm.setValue("");
    ed_srchAsetCostCd.focus();
};

/**
* ž°įŪöĆŽ≤ĄŪäľ
*/
scwin.f_Retrieve = async function() {
    if (ds_master.getRowCount() > 0 && ds_master.getModifiedIndex().length > 0) {
        if (! await $c.win.confirm(MSG_CM_CRM_005)) {
            return;
        }
    }
    scwin.setInit();
    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        let rowCnt = ds_master.getRowCount();
        if (rowCnt == 0) {
            $c.gus.cfAlertMsg(MSG_CM_WRN_002); // ž°įŪöĆÍ≤įÍ≥ľÍįÄ ž°īžě¨ŪēėžßÄ žēäžäĶŽčąŽč§
        } else {
            scwin.load_row = scwin.load_row == 0 ? 1 : scwin.load_row;
            tv_treeView.findNodeByIndex(scwin.load_row, true);
            tv_treeView.focus();
        }

        if($c.gus.cfCheckCreateFlag()){
            $c.gus.cfTurnCreateFlag(false);
        }
    }
};

scwin.sbm_retrieve_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
};


/**
 * ŪĖČž∂ĒÍįÄ
 */
scwin.f_Add = async function() {
    if (await $c.gus.cfCheckCreateFlag()) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_008, [""]);
        return;
    }

    let row = ds_master.getRowPosition();

    if (ds_master.getRowCount() > 0) {
        if(!await scwin.f_ValidateRow(row)) {
            return;
        }
    } 

    //žěźžāįŽĻĄžö©žĹĒŽďú
    if ($c.gus.cfIsNull(ds_master.getCellData(row, "asetCostCd"))) {
        await $c.gus.cfAlertMsg("žÉĀžúĄ žěźžāįŽĻĄžö©žĹĒŽďúÍįÄ ž†Äžě•ŽźėžßÄ žēäžēėžäĶŽčąŽč§.");
        return;
    }

    //let checkLevel  = tv_treeView.ItemLevel;
    var node = tv_treeView.getSelectedNode();
    checkLevel = node ? node.depth + 1 : 1;

    let asetCostLvl = ds_master.getCellData(row, "asetCostLvl");
    // let comboIndex  = acb_asetCostLvl.IndexOfColumn("code", asetCostLvl + 1);

    var newRow;
    if (row === ds_master.getRowCount() - 1 || ds_master.getRowCount() === 0) {
        newRow = ds_master.insertRow();
    } else {
        newRow = ds_master.insertRow(row + 1);
    }

    ds_master.setCellData(newRow, "checkLevel"      , checkLevel);
    ds_master.setCellData(newRow,"upperAsetCostCd"  , ds_master.getCellData(row, "asetCostCd"));
    ds_master.setCellData(newRow,"upperAsetCostCdNm", ds_master.getCellData(row, "asetCostCdNm"));
    ds_master.setCellData(newRow,"acctClsCd"        , ds_master.getCellData(row, "acctClsCd"));
    //žěźžāįŽĻĄžö©Ž†ąŽ≤® +1
    ds_master.setCellData(newRow,"asetCostLvl"      , Number(asetCostLvl)+1);
    ds_master.setCellData(newRow,"aggrClsCd"        , ds_master.getCellData(row, "aggrClsCd"));
    ed_upperAsetCostCd.hidVal = ds_master.getCellData(row, "asetCostCd");
    ds_master.setCellData(newRow,"useYn"            , scwin.DGlobalValue.TRUE);
    ds_master.setCellData(newRow,"sortSeq"          , 0);

    // tv_treeView.reset();
    // tv_treeView.index = row + 1;
    tv_treeView.findNodeByIndex(newRow + 1, true);
    tv_treeView.focus();

    $c.gus.cfEnableObjects(tbl_asetCost);
    $c.gus.cfDisableKey();
    $c.gus.cfEnableObjects([ed_upperAsetCostCd, ed_mgntAcctCd]);
    $c.gus.cfDisableBtn([btn_update]);

    ed_asetCostCdNm.focus();
};

/**
 * ŪĖČžā≠ž†ú
 * TOBE žā¨žö©žēąŪē®(ASIS ž£ľžĄĚž≤ėŽ¶¨)
 */
scwin.f_Delete = async function() {
    //ž°įŪöĆŪēėžßÄ žēäžĚÄ Í≤Ĺžöį
    if ($c.gus.cfCheckCreateFlag()) {
        // MSG_CM_WRN_008   =  "Í≤ÄžÉČŪēú ŽćįžĚīŪĄįÍįÄ ž°īžě¨ŪēėžßÄ žēäžäĶŽčąŽč§.<BR>Ž®ľž†Ä @Í≤ÄžÉČžĚĄ Ūēėžč≠žčúžė§."
        await $c.gus.cfAlertMsg(MSG_CM_WRN_008, [""]);
        return;
    }

    if (ds_master.getRowCount() == 0) {
        // MSG_CM_ERR_003   = "ŪēīŽčĻŽźėŽäĒ žěźŽ£ĆÍįÄ ž°īžě¨ŪēėžßÄ žēäžäĶŽčąŽč§."
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        return;
    }

    //žěźžčĚžēĄžĚīŪÖúžĚī žěąŽäĒ žßÄ ž≤īŪĀ¨
    if (scwin.f_HasChild(ds_master.getCellData(ds_master.getRowPosition(), "asetCostCd")) == true) {
        await $c.gus.cfAlertMsg("ŪēėžúĄ žěźžāįŽĻĄžö©žĹĒŽďúÍįÄ ž°īžě¨Ūē©ŽčąŽč§.");
        return;
    }

    $c.gus.cfInitHidVal();
    ds_master.deleteRow(ds_master.getRowPosition());
    $c.gus.cfDisableBtn([btn_Update]);

    //ExpandLevelžóź ŪäĻž†ē LevelÍįížĚĄ žĄ§ž†ēŪēėŽ©ī, žĄ§ž†ēŽźú LevelŽ≥īŽč§ žÉĀžúĄžóź žěąŽäĒ Ž™®Žď† ItemžĚĄ ŪéľžĻúŽč§
    // tv_treeView.ExpandLevel = scwin.maxLevel;
    expandToLevel(tv_treeView, scwin.maxLevel);

    if (ds_master.getRowCount() == 0) {
        $c.gus.cfDisableObjects(tbl_asetCost);
        if (ds_master.getModifiedIndex().length > 0) {
            if (await $c.win.confirm(MSG_CM_CRM_015)) {
                await scwin.f_Save();
            }
        }
    } else {
        $c.gus.cfDisableKey();
        $c.gus.cfEnableObjects([udc_srchAsetCostCd]);
    }
};

/**
 * ŪäĻž†ēŽÖłŽďú ŪéľžĻėÍłį
 */
function expandToLevel(treeId, level) {
    const tree  = treeId;
    for (let i = 0; i < ds_master.getRowCount(); i++) {
        const nodeLevel = ds_master.getCellData(i, "level"); // ŽćįžĚīŪĄįžÖčžóź level žĽ¨Žüľ žěąŽč§Í≥† ÍįÄž†ē
        const nodeId    = ds_master.getCellData(i, "id");    // ŽÖłŽďú id žĽ¨Žüľ
        if (nodeLevel <= level) {
            tree.expandNode(nodeId);
        }
    }
};

/**
 * ž∑®žÜĆ
 */
scwin.f_Cancel = function() {
    if ($c.gus.cfCheckCreateFlag()) {
        // MSG_CM_WRN_008   =  "Í≤ÄžÉČŪēú ŽćįžĚīŪĄįÍįÄ ž°īžě¨ŪēėžßÄ žēäžäĶŽčąŽč§.<BR>Ž®ľž†Ä @Í≤ÄžÉČžĚĄ Ūēėžč≠žčúžė§."
        $c.win.alert(MSG_CM_WRN_008);
        return;
    }

    if (ds_master.getModifiedIndex().length < 1) {
        // MSG_CM_ERR_003   = "ŪēīŽčĻŽźėŽäĒ žěźŽ£ĆÍįÄ ž°īžě¨ŪēėžßÄ žēäžäĶŽčąŽč§."
        $c.win.alert(MSG_CM_ERR_003);
        return;
    }

    $c.gus.cfInitHidVal();
    var row = ds_master.getRowPosition();
    if (ds_master.getRowStatus(row) == "C") {
        ds_master.removeRow(row)
        if(row == 0) {
            row = row+1;
        }
    } else {
        ds_master.undoRow(row);
        row = row+1;
    }
    //disable ž≤ėŽ¶¨
    $c.gus.cfDisableObjects(tbl_asetCost);
    $c.gus.cfDisableBtn([btn_save]);

    tv_treeView.focus();
    tv_treeView.findNodeByIndex(row, true);
};

/**
 * žąėž†ēŽ≤ĄŪäľ
 */
scwin.f_Update = function() {
    if (ds_master.getRowCount() == 0) {
        // MSG_CM_ERR_003   = "ŪēīŽčĻŽźėŽäĒ žěźŽ£ĆÍįÄ ž°īžě¨ŪēėžßÄ žēäžäĶŽčąŽč§."
        $c.win.alert(MSG_CM_ERR_003);
        return;
    }

    // disable ž≤ėŽ¶¨
    $c.gus.cfEnableObjects([tbl_asetCost]);
    $c.gus.cfDisableKey();
    $c.gus.cfEnableObjects([udc_srchAsetCostCd, ed_upperAsetCostCd, ed_mgntAcctCd]);
    $c.gus.cfDisableBtn([btn_update]);

    //focus žĄ§ž†ē
    ed_asetCostCdNm.focus();
};

/**
 * ž†Äžě•
 */
scwin.f_Save = async function() {
    //Ž≥ÄÍ≤ĹŪēú ŽćįžĚīŪĄįÍįÄ žěąŽäĒžßÄ ž≤īŪĀ¨ŪēúŽč§.
    // if (ds_master.IsUpdated == false) {
    if (ds_master.getModifiedIndex().length < 1) {
        // MSG_CM_ERR_001   = "@žĚÄ(ŽäĒ) Ž≥ÄÍ≤ĹŽźú žā¨Ūē≠žĚī žóÜžäĶŽčąŽč§."
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["žěźžāįŽĻĄžö©žāįž†ēÍłįž§Ä"]);        
        return;
    }
    let ret = await scwin.f_Validate();
    if (!ret) {
        return false;
    }
    if (await $c.win.confirm(MSG_CM_CRM_001) ) {
        scwin.load_row = ds_master.getRowPosition();
	    sbm_save.userData1="noError";
        $c.sbm.execute(sbm_save);
    }
};

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        await $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
        return;
    }

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        ds_master.reform();
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);
        $c.sbm.execute(sbm_retrieve);
    }
};

scwin.sbm_save_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
};

/**
 * Validation
 */
scwin.f_Validate = async function() {
    //Validation check
    for (j = 0; j < ds_master.getRowCount(); j++) {
        if (ds_master.getRowStatus(j) != "R") {
            let ret = await scwin.f_ValidateRow(j);
            if (!ret) {
                return false;
            }
        }
    }
    return true;
};

/**
 * Row Validation
 */
scwin.f_ValidateRow = async function (row) {
    ds_master.setRowPosition(row);
    // let ret = await $c.gus.cfValidate([tbl_asetCost]);
    //žěźžāįŽĻĄžö©žĹĒŽďúŽ™Ö
    let ret = await $c.gus.cfValidate([ed_asetCostCdNm]);
    if (!ret) {
        return false;
    }
    var upperAsetCostCd = ds_master.getCellData(row, "upperAsetCostCd");
    var mgntAcctCd      = ds_master.getCellData(row, "mgntAcctCd");

    if (ds_master.getCellData(row, "asetCostLvl") == scwin.rootLevel) {
        if (!$c.gus.cfIsNull(upperAsetCostCd)) {
            //MSG_CM_ERR_041 = "@žĚÄ(ŽäĒ) @Ūē† žąė žóÜžäĶŽčąŽč§."
            // await $c.win.alert(MSG_CM_ERR_041, ["žěźžāįŽĻĄžö©Ž†ąŽ≤®žĚī 1žĚľÍ≤Ĺžöį,žÉĀžúĄÍ≥Ąž†ēžĚĄ ŽďĪŽ°Ě"]);
            await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["žěźžāįŽĻĄžö©Ž†ąŽ≤®žĚī 1žĚľÍ≤Ĺžöį", "žÉĀžúĄÍ≥Ąž†ēžĚĄ ŽďĪŽ°Ě"]);
            ed_upperAsetCostCd.focus();
            return false;
        }

    } else {
        if ($c.gus.cfIsNull(upperAsetCostCd)) {
            //MSG_CM_ERR_053   =  "@žĚī(ÍįÄ) ŽąĄŽĚĹŽźėžóąžäĶŽčąŽč§."
            // await $c.win.alert(MSG_CM_ERR_053, ["žÉĀžúĄÍ≥Ąž†ēžĹĒŽďú"]);
            await $c.gus.cfAlertMsg(MSG_CM_ERR_053, ["žÉĀžúĄÍ≥Ąž†ēžĹĒŽďú"]);
            ed_upperAsetCostCd.focus();
            return false;
        }

        if (ds_master.getRowCount() > 1) {
            // var upperLevelRow = ds_master.getCellDataRow("asetCostCd", upperAsetCostCd);
            var upperLevelRow = ds_master.getMatchedIndex("asetCostCd", upperAsetCostCd);
            if (ds_master.getCellData(row, "asetCostLvl") == ds_master.getCellData(upperLevelRow[0], "asetCostLvl")) {
                await $c.gus.cfAlertMsg("ŽŹôžĚľŽ†ąŽ≤®žĚė Ūē≠Ž™©žĚī žÉĀžúĄÍ≥Ąž†ēžĹĒŽďúÍįÄ Žź† žąė žóÜžäĶŽčąŽč§.");
                ed_upperAsetCostCd.focus();
                return false;
            }
        }
    }

    if (!$c.gus.cfIsNull(upperAsetCostCd) && upperAsetCostCd != ed_upperAsetCostCd.hidVal) {
        // MSG_CM_ERR_038   =  "žú†Ūö®Ūēú @ÍįÄ žēĄŽčôŽčąŽč§."
        // await $c.win.alert(MSG_CM_ERR_038, ["žÉĀžúĄÍ≥Ąž†ēžĹĒŽďú"]);
        await $c.gus.cfAlertMsg(MSG_CM_ERR_038, ["žÉĀžúĄÍ≥Ąž†ēžĹĒŽďú"]);
        return false;
    }

    if (!$c.gus.cfIsNull(mgntAcctCd) && mgntAcctCd != ed_mgntAcctCd.hidVal) {
        // MSG_CM_ERR_038   =  "žú†Ūö®Ūēú @ÍįÄ žēĄŽčôŽčąŽč§."
        // await $c.win.alert(MSG_CM_ERR_038, ["ÍīÄŽ¶¨Í≥Ąž†ēžĹĒŽďú"]);
        await $c.gus.cfAlertMsg(MSG_CM_ERR_038, ["ÍīÄŽ¶¨Í≥Ąž†ēžĹĒŽďú"]);
        return false;
    }

    //TODO : ž†ēŽ†¨žąúŽ≤ą 0žěÖŽ†• žēąŽźėÍ≤Ć ž∂ĒÍįÄ
    if (ed_sortSeq.getValue() < 1) {
        await $c.gus.cfAlertMsg("ž†ēŽ†¨žąúŽ≤ąžĚÄ(ŽäĒ) 1 žĚīžÉĀžúľŽ°ú žěÖŽ†•Ūēėžč≠žčúžė§.");
        ed_sortSeq.focus();
        return false;
    }

    return true;
};

/**
 * scwin.f_ValidationSync žā¨žö©ŪēėÍłį žúĄŪēú Ūē®žąė
 */
scwin.myCfValidate = function (oElement) {
    let obj = $c.gus.object(oElement);
    if (obj.length != null) {
		for (var i = 0; i < obj.length; i++) {
            let id = obj[i];
            if($c.gus.cfIsNull(id.getValue())) {
                $c.win.alert(id.options.title + "žĚÄ(ŽäĒ) ŪēĄžąė žěÖŽ†• Ūē≠Ž™©žěÖŽčąŽč§.");
                id.focus();
                return false;
            }
        }
    }
    return true;
};

/**
 * onbeforerowpositionchange žā¨žö©žĚĄ žúĄŪēú validation ž≤īŪĀ¨
 */
scwin.f_ValidationSync = function() {
    //ŪēĄžąėÍįí žěĄžĚėŽ°ú ž≤īŪĀ¨(žěźžāįŽĻĄžö©žĹĒŽďú, žÉĀžúĄÍ≥Ąž†ēžĹĒŽďú)
    let ret = scwin.myCfValidate([ed_asetCostCdNm, ed_upperAsetCostCd, ed_upperAsetCostCdNm]);
    if (!ret) {
        return false;
    }
    return true;
};


/**
 * ž°įŪöĆ ŽćįžĚīŪĄįžÖč Ūó§ŽćĒ žÉĚžĄĪ
 * TOBE žā¨žö©žēąŪē®
 */
scwin.f_HeaderCreate = function() {
    // var GAUCE_DATASET_HEADER = "asetCostCd:STRING"
    //     + ",asetCostCdNm:STRING"
    //     + ",useYn:INT(1)";
    // ds_search.SetDataHeader(GAUCE_DATASET_HEADER);
