/**
 * DataListžĚė rowPositionžĚī Ž≥ÄÍ≤ĹŽźú Í≤Ĺžöį ŽįúžÉĚ
 */
scwin.ds_master_onrowpositionchange = function (info) {
    ed_upperAsetCostCd.hidVal = ds_master.getCellData(info.newRowIndex, "upperAsetCostCd");    
    ed_mgntAcctCd.hidVal      = ds_master.getCellData(info.newRowIndex, "mgntAcctCd");    
    if (ds_master.getRowStatus(info.newRowIndex) == "C") {
        $c.gus.cfEnableKeyData();
        $c.gus.cfEnableObjects(tbl_asetCost);
        $c.gus.cfDisableObjects([ed_asetCostCd]);
        $c.gus.cfDisableBtn([btn_update]);
    }else if(ds_master.getRowStatus(info.newRowIndex) == "U") {
        //žąėž†ēŽ≤ĄŪäľ
        scwin.f_Update();
    }else {
        $c.gus.cfDisableObjects(tbl_asetCost);
        $c.gus.cfDisableBtn([btn_save]);
    }
};

/**
 * DataListžĚė rowPositionžĚī Ž≥ÄÍ≤ĹŽźėÍłį žßĀž†Ąžóź ŽįúžÉĚŪēėŽ©į rowPositionžĚė Ž≥ÄÍ≤Ĺ ž†Āžö© žó¨Ž∂ÄŽ•ľ Í≤įž†ē
 * asis : Í∑łŽ¶¨Žďú Ž°úžöįŽ•ľ Ž≥ÄÍ≤ĹŪēėŽ†§Í≥† Ūē† Í≤Ĺžöį - ŪēĄžąėŪē≠Ž™© ž≤īŪĀ¨
 * tobe : ŪėĄžě¨ $c.gus.cfValidate žā¨žö© žčú asyncŽĚľ žĚīŽ≤§Ūäłžóź asyncž£ľŽ©ī return falsežēąŽ®ĻŪěė
 */
scwin.ds_master_onbeforerowpositionchange =  function (info) {
    if (ds_master.getRowStatus(info.oldRowIndex) == "U" || ds_master.getRowStatus(info.oldRowIndex) == "C") {
        let ret = scwin.f_ValidationSync();
        if(ret == false) {
            tv_treeView.findNodeByIndex(info.oldRowIndex + 1, true);
        }
        return ret;
    }
};
